var minimumTotal = function(triangle) {
    const best = triangle[triangle.length - 1].slice();
    for (let i = triangle.length - 2; i >= 0; i--) {
        for (let j = 0; j < triangle[i].length; j++) {
            best[j] = triangle[i][j] + Math.min(best[j], best[j + 1]);
        }
    }
    return best[0];
